import { SHOW_LOADER } from '../actions/types'
import { HIDE_LOADER } from '../actions/types'


const initialState = {
    loading: false
}


export function appReducer(state = initialState, action) {
    switch (action.type) {
        case SHOW_LOADER:
            return { ...state, loading: true }
        case HIDE_LOADER:
            return { ...state, loading: false }
        default:
            return state
    }
}