import React, { Component } from 'react'
import { connect } from 'react-redux'
import './Ingridients.scss'
import Ingridient from '../../components/Ingridient'
import { AddToBar } from '../../actions/addIngridientBar'
import { AddToAvialableCoctails } from '../../actions/addToAvialableCoctails'


class Ingridients extends Component {

    addCoctailToAvialable = () => {
        const { setAddToAvialableCoctails } = this.props

        let barItemsNames
        let suitableСocktail = []

        if (this.props.bar.length === 0) {
            barItemsNames = this.props.bar.name
        } else {
            barItemsNames = this.props.bar.map((item) => {
                return item.name
            })
        }

        this.props.coctails.map((coctail) => {
            for (let property in coctail.composition) {
                if (barItemsNames.includes(coctail.composition[property].name)) {
                    suitableСocktail.push(coctail)
                }
            }
            return coctail
        })

        var uniq = Array.from(new Set(suitableСocktail));
        setAddToAvialableCoctails(uniq)
    }

    addBar = (item) => {
        const { bar, AddToBar } = this.props

        if (!bar.some(elem => elem.id === item.id)) {
            AddToBar(item)
        }

        setTimeout(this.addCoctailToAvialable, 500)
    }

    render() {
        const { data } = this.props

        const ingridients = data.map((item, i) => {
            return (
                <Ingridient
                    item={item}
                    key={i}
                    addBar={this.addBar}
                />
            )
        })

        return (
            <div className="ingridients">
                <div className="container">
                    <h2 className="ingridients__title">Ингридиенты</h2>
                    <div className="my-bar__ingridients">
                        <ul className="ingridients__list">
                            {ingridients}
                        </ul>
                    </div>
                </div>
            </div>
        )
    }
}


const mapStateToProps = store => {
    return {
        data: store.data.ingridients,
        bar: store.bar
    }
}


const mapDispatchToProps = dispatch => {
    return {
        AddToBar: ingridient => dispatch(AddToBar(ingridient)),
        setAddToAvialableCoctails: coctail => dispatch(AddToAvialableCoctails(coctail)),
    }
}

export default connect(mapStateToProps, mapDispatchToProps)(Ingridients)