import React from 'react'
import './RandomCoctailItem.scss'

const RandomCoctailItem = (props) => {
    const { strDrink, strInstructions, strDrinkThumb, strIBA } = props.coctailData

    return (
        <div className="random-coctail-item">
            <div className="container random-coctail-item__container">
                <div className="random-coctail-item__wrap-img">
                    <img src={strDrinkThumb} alt={strDrink} />
                </div>
                <div>
                    <div className="random-coctail-item__name">{strDrink}</div>
                    <div className="random-coctail-item__instruction">{strInstructions}</div>
                    <div>{strIBA}</div>
                </div>
            </div>
        </div>
    )
}

export default RandomCoctailItem