import React, { Component } from 'react'
import { connect } from 'react-redux'
import BarItem from '../../components/BarItem'
import './Bar.scss'

import { AddToBasket } from '../../actions/addBasket'
import { removeIngridientInBar } from '../../actions/removeIngridientInBar'


class Bar extends Component {

    addBasket = (barItem) => {
        const { basket, setAddToBasket } = this.props

        if (basket.length === 0) {
            setAddToBasket(barItem)
        } else {
            let contain = basket.some((element) => { return element.id === barItem.id })
            if (!contain) {
                setAddToBasket(barItem)
            }
        }
    }

    removeFromBar = (barItem) => {
        const { bar, removeIngridientInBar } = this.props

        let values = bar.filter(function (x) { return x.name !== barItem.name })
        removeIngridientInBar(values)

        //addCoctailToAvialable()
    }

    addCoctailToAvialable = () => {
        const { bar, coctails, setAddToAvialableCoctails } = this.props;
        
        let barItemsNames
        let suitableСocktail = []

        if (bar.length === 0) {
            barItemsNames = bar.name
        } else {
            barItemsNames = bar.map((item) => {
                return item.name
            })
        }

        coctails.map((coctail) => {
            //console.log(coctail.composition) //Состав коктейля
            for (let property in coctail.composition) {
                //console.log(coctail.composition[property].name)
                if (barItemsNames.includes(coctail.composition[property].name)) {
                    //console.log(coctail.idDrink)
                    suitableСocktail.push(coctail)
                }
            }
            return coctail
        })

        //console.log('suitableСocktail', suitableСocktail)

        var uniq = Array.from(new Set(suitableСocktail));
        //console.log('uniq', uniq)
        console.log('zzzzz', bar)
        setAddToAvialableCoctails(uniq)
    }


    generateBarItem = () => {
        const { bar, coctails } = this.props

        if (bar.length > 0) {
            return (bar.map((item, i) => {
                return (
                    <BarItem
                        {...item}
                        bar={bar}
                        coctails={coctails}
                        removeFromBar={this.removeFromBar}
                        addBasket={this.addBasket}
                        key={i}
                    />
                )
            }))
        }
    }

    render() {

        return (
            <div className="my-bar">
                <div className="container my-bar__container">
                    <h2 className="my-bar__title">Мой бар</h2>
                    <div className="my-bar__blocks">
                        {this.generateBarItem()}
                    </div>
                </div>
            </div>
        )
    }
}


const mapStateToProps = store => {
    return {
        bar: store.bar,
        basket: store.basket,
    }
}


const mapDispatchToProps = dispatch => {
    return {
        removeIngridientInBar: ingridient => dispatch(removeIngridientInBar(ingridient)),
        setAddToBasket: goods => dispatch(AddToBasket(goods)),
    }
}

export default connect(mapStateToProps, mapDispatchToProps)(Bar)