import React from 'react'
import { connect } from 'react-redux'
import './FullCategory.scss'
import Coctail from '../../components/Coctail'


const FullCategory = (props) => {
    const { coctails: coctailsData, coctailCategory } = props
    let matchingСocktails = []
    let nameCategory

    for (let item of coctailsData) {
        if (item.categoryID === coctailCategory) {
            matchingСocktails.push(item)
            nameCategory = item.category
        }
    }

    let coctails = matchingСocktails.map((item) => {
        return (
            <Coctail coctailInfo={item} key={item.idDrink} />
        )
    })

    return (
        <>
            <div className="full-category">
                <div className="container">
                    <h2 className="full-category__title">{nameCategory}</h2>
                    <div className="full-category__blocks">
                        {coctails}
                    </div>
                </div>
            </div>
        </>
    )
}


const mapStateToProps = store => {
    return {
        coctails: store.data.drinks
    }
}


export default connect(mapStateToProps)(FullCategory)