import { FETCH_COCTAILS } from '../actions/types'

const initialState = {
    fetchedPosts: {},
    isEmpty: true
}


export function fetchCoctails(state = initialState, action) {
    switch (action.type) {
        case FETCH_COCTAILS:
            return { ...state, 
                fetchedPosts: action.payload,
                isEmpty: false
            }
        default:
            return state
    }
}