import React, { Component } from 'react'
import { connect } from 'react-redux'
import { Route, Switch } from 'react-router-dom'
import './App.scss'

import About from '../../components/About'
import FullBasket from '../../components/FullBasket'
import Header from '../../components/Header'
import Footer from '../../components/Footer'
import Bar from '../Bar'
import AvailableCoctails from '../../components/AvailableCoctails'
import FullCategory from '../FullCategory'
import CoctailDetail from '../../components/CoctailDetail'
import Ingridients from '../Ingridients'
import RandomCoctails from '../RandomCoctails'


class App extends Component {
	render() {
		const { data, basket, totalPrice, availableCoctails } = this.props

		return (
			<>
				<div className="content">
					<Header />

					<Switch>
						<Route exact path='/Coctail-app/'>
							<Ingridients coctails={data.drinks} />

							<Bar />

							<AvailableCoctails availableCoctails={availableCoctails} />
						</Route>

						<Route exact path='/Coctail-app/about'>
							<About />
						</Route>

						<Route path='/Coctail-app/the-coctail-db'>
							<RandomCoctails />
						</Route>

						<Route path='/Coctail-app/full-basket'>
							<FullBasket
								totalPrice={totalPrice}
								basket={basket}
								ingridients={data.ingridients}
							/>
						</Route>

						<Route
							path='/Coctail-app/categories/:id'
							render={({ match }) => {
								const { id } = match.params;
								return <FullCategory coctailCategory={id} />
							}} />

						<Route
							path='/Coctail-app/coctail/:id'
							render={({ match }) => {
								const { id } = match.params;
								return <CoctailDetail coctailNumber={id} coctails={this.props.data.drinks} />
							}} />
					</Switch>
				</div>
				<Footer />
			</>
		);
	}
}


const mapStateToProps = store => {
	return {
		data: store.data,
		basket: store.basket,
		availableCoctails: store.availableCoctails,
		totalPrice: store.basket.reduce((sum, p) => { sum += p.price * p.quantity; return sum; }, 0)
	}
}


export default connect(mapStateToProps)(App);