import { ADD_TO_AVAILABLE_COCTAILS } from '../actions/types'


const initialState = {
    prod: []
}


export function availableCoctailsReducer(state = initialState, action) {
    switch (action.type) {
        case ADD_TO_AVAILABLE_COCTAILS:
            return {
                ...state,
                prod: action.payload
            }
        default:
            return state
    }
}