import React, { Component } from 'react'
import './CoctailDetail.scss'
import Table from '../Table'


export default class CoctailDetail extends Component {

	findCoctail = () => {
		let coctail
		this.props.coctails.map((item) => {
			if (this.props.coctailNumber === item.idDrink) {
				coctail = item
			}
			return (
				null
			)
		})
		return coctail
	}

	generateTags = (tags) => {
		return (tags.map((tag) => { return (<div className="tag" key={tag}>{tag}</div>) }))
	}

	render() {
		let coctail = this.findCoctail()

		return (
			<>
				<div className="container">
					<div className="coctail-detail">

						<div className="coctail-detail__top">
							<div>
								<h1 className="coctail-detail__name">{coctail.nameDrink}</h1>
								<img className="coctail-detail__img" src={coctail.image} alt={coctail.nameDrink} />
							</div>
							<Table
								composition={coctail.composition}
							/>
						</div>

						<div className="coctail-detail-instraction">
							<span className="coctail-detail-instraction__title">Инструкция</span>
							<p className="coctail-detail-instraction__text">{coctail.Instructions}</p>
						</div>

						<div className="tags">
							{this.generateTags(coctail.tags)}
						</div>

					</div>
				</div>
			</>
		)
	}
}