import React from 'react'
import './FullBasket.scss'
import BasketItem from '../BasketItem'


const FullBasket = (props) => {

    const generateTableData = () => {
        return (props.basket.map((item, i) => {
            return <BasketItem detailInfo={item} key={i} />
        }))
    }

    return (
        <div className="full-basket">
            <div className="container full-basket__container">
                <h1 className="full-basket__title">Оформление заказа</h1>

                <div className="full-basket-all">
                    <span className="full-basket-all__title">Товары в корзине</span>

                    {!props.basket.length && <p className="shelf-empty">Добавьте товары в корзину <br /></p>}

                    {props.basket.length > 0 && <div>{generateTableData()}</div>}

                    {props.basket.length > 0 && <div className="full-basket-total">
                        <p className="full-basket-total__desc">Товаров на сумму: <span className="">{props.totalPrice}</span> ₽</p>
                    </div>}

                </div>
            </div>
        </div>
    )
}


export default FullBasket